 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Pooling Functions
 26→
 27→void riscv_nn_avepool_HWC_s8(q7_t * in_tensor,
 28→                             const uint16_t in_tensor_batch,
 29→                             const uint16_t in_tensor_dim,
 30→                             const uint16_t in_tensor_ch,
 31→                             const uint16_t ker_dim,
 32→                             const uint16_t pad,
 33→                             const uint16_t stride,
 34→                             const uint16_t out_tensor_dim,
 35→                             q7_t * in_tmp_buf,
 36→                             q7_t * out_tensor)
 37→{
 38→#ifdef ENA_EMPTY_FUN
 39→    //empty body
 40→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC) && 0
 41→    // the v-ext algorithm is modifed, please remember to update the intrinsic version v-ext algorithm
 42→
 43→    long out_x, out_y, k_x, k_y, in_x, in_y;
 44→
 45→    for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
 46→    {
 47→        long ker_y_start = MAX(0, in_y);
 48→        long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
 49→        for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
 50→        {
 51→            long count = 0;
 52→            long ker_x_start = MAX(0, in_x);
 53→            long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
 54→            long cur_ch = 0, vl = 0;
 55→
 56→            //calculate the numbers of kernel nodes in the range of input tensor
 57→            for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 58→            {
 59→                for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 60→                {
 61→                    count++;
 62→                }
 63→            }
 64→
 65→            long in_tensor_ch2 = in_tensor_ch;
 66→            while(in_tensor_ch2 > 0)
 67→            {
 68→                // reset the accumulators
 69→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 70→                vint16m8_t vAcc_i16 = __riscv_vundefined_i16m8();
 71→                vAcc_i16 = __riscv_vand(vAcc_i16, 0, vl);
 72→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 73→
 74→                for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 75→                {
 76→                    for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 77→                    {
 78→                        q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
 79→                        vint8m4_t vIn_ptr_i8 = __riscv_vle8_v_i8m4(in_ptr, vl);
 80→                        vAcc_i16 = __riscv_vwadd_wv(vAcc_i16, vIn_ptr_i8, vl);
 81→                    }
 82→                }
 83→
 84→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 85→                vAcc_i16 = __riscv_vdiv(vAcc_i16, count, vl);
 86→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 87→                vint8m4_t vResult_i8 = __riscv_vnsra(vAcc_i16, 0, vl);
 88→                __riscv_vse8(out_tensor, vResult_i8, vl);
 89→                out_tensor += vl;
 90→                cur_ch += vl;
 91→                in_tensor_ch2 -= vl;
 92→            }
 93→        }
 94→    }
 95→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
 96→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
 97→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
 98→
 99→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
100→    {
101→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
102→        {
103→            long ker_y_start = MAX(0, in_y);
104→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
105→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
106→            {
107→                long ker_x_start = MAX(0, in_x);
108→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
109→                long cur_ch = 0, vl = 0;
110→
111→                if ((ker_y_end > ker_y_start) &&
112→                    (ker_x_end > ker_x_start))
113→                {
114→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
115→                    // Fixed-point reciprocal for division: multiplier = ceil(2^16 / count)
116→                    // vmulh.vx at e16 computes (val * multiplier) >> 16
117→                    // Using ceiling ensures we don't under-estimate for positive values.
118→                    // For negative values, arithmetic right shift rounds toward -inf
119→                    // instead of C's truncation toward zero, so we add (count-1) to
120→                    // negative accumulators before the multiply to correct this.
121→                    long multiplier = ((1L << 16) + count - 1) / count;
122→                    long in_tensor_ch2 = in_tensor_ch;
123→                    // Precompute row stride for pointer advancement
124→                    long row_stride = in_tensor_dim * in_tensor_ch;
125→
126→                    while(in_tensor_ch2 > 0)
127→                    {
128→                        // Use e8/M4 -> s16 widening (VL=512 at VLEN=1024)
129→                        // instead of e8/M2 -> s32 quad-widening (VL=256)
130→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
131→                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
132→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
133→
134→                        q7_t *row_ptr = in_tensor + (ker_y_start * row_stride) + (ker_x_start * in_tensor_ch) + cur_ch;
135→                        for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
136→                        {
137→                            q7_t *col_ptr = row_ptr;
138→                            for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
139→                            {
140→                                NDS_VEC_VLE8_V(NDS_VEC_V8, col_ptr);
141→                                NDS_VEC_VWADD_WV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
142→                                col_ptr += in_tensor_ch;
143→                            }
144→                            row_ptr += row_stride;
145→                        }
146→
147→                        // Fixed-point reciprocal multiply instead of VDIV:
148→                        // For negative accumulators, add (count-1) before multiply
149→                        // to convert floor-rounding to truncation-toward-zero.
150→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
151→                        NDS_VEC_VSRA_VI(NDS_VEC_V16, NDS_VEC_V0, 15);   // sign mask: 0 if >=0, -1 if <0
152→                        NDS_VEC_VAND_VX(NDS_VEC_V16, NDS_VEC_V16, count - 1); // 0 if >=0, (count-1) if <0
153→                        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16); // bias negatives toward zero
154→                        NDS_VEC_VMULH_VX(NDS_VEC_V0, NDS_VEC_V0, multiplier);
155→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
156→                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
157→                        NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
158→                        out_tensor += vl;
159→                        cur_ch += vl;
160→                        in_tensor_ch2 -= vl;
161→                    }
162→                }
163→                else
164→                {
165→                    // for those outputs in boundary as there is no overlapping
166→                    // between ifm and kernel
167→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
168→                    out_tensor += in_tensor_ch;
169→                }
170→            }
171→        }
172→        in_tensor += input_len;
173→    }
174→#elif defined(ENA_DSP_ISA_64)
175→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
176→    const long_t cst_one_q15x4 = 0x0001000100010001;
177→
178→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
179→    {
180→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
181→        {
182→            long ker_y_start = MAX(0, in_y);
183→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
184→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
185→            {
186→                long ker_x_start = MAX(0, in_x);
187→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
188→                uint32_t cur_ch;
189→
190→                if ((ker_y_end > ker_y_start) &&
191→                    (ker_x_end > ker_x_start))
192→                {
193→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
194→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
195→                    {
196→                        suni_t sum_q31x2_0;
197→                        suni_t sum_q31x2_1;
198→                        suni_t sum_q31x2_2;
199→                        suni_t sum_q31x2_3;
200→                        sum_q31x2_0.l0 = 0;
201→                        sum_q31x2_1.l0 = 0;
202→                        sum_q31x2_2.l0 = 0;
203→                        sum_q31x2_3.l0 = 0;
204→
205→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
206→                        {
207→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
208→                            {
209→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
210→                                suni_t in_q7x8 = simd_load_8(pIn, 0);
211→                                long in_q15x4_0 = NDS_DSP_SUNPKD810(in_q7x8.l0);
212→                                long in_q15x4_1 = NDS_DSP_SUNPKD832(in_q7x8.l0);
213→                                sum_q31x2_0.l0 = NDS_DSP_KMABB(sum_q31x2_0.l0, in_q15x4_0, cst_one_q15x4);
214→                                sum_q31x2_1.l0 = NDS_DSP_KMATT(sum_q31x2_1.l0, in_q15x4_0, cst_one_q15x4);
215→                                sum_q31x2_2.l0 = NDS_DSP_KMABB(sum_q31x2_2.l0, in_q15x4_1, cst_one_q15x4);
216→                                sum_q31x2_3.l0 = NDS_DSP_KMATT(sum_q31x2_3.l0, in_q15x4_1, cst_one_q15x4);
217→                            }
218→                        }
219→
220→                        suni_t out_q7x8;
221→                        out_q7x8.b8.b0 = sum_q31x2_0.b32.w0 / count;
222→                        out_q7x8.b8.b1 = sum_q31x2_1.b32.w0 / count;
223→                        out_q7x8.b8.b2 = sum_q31x2_2.b32.w0 / count;
224→                        out_q7x8.b8.b3 = sum_q31x2_3.b32.w0 / count;
225→                        out_q7x8.b8.b4 = sum_q31x2_0.b32.w1 / count;
226→                        out_q7x8.b8.b5 = sum_q31x2_1.b32.w1 / count;
227→                        out_q7x8.b8.b6 = sum_q31x2_2.b32.w1 / count;
228→                        out_q7x8.b8.b7 = sum_q31x2_3.b32.w1 / count;
229→                        simd_save_8((s8_t*)out_tensor, out_q7x8.l0);
230→                        out_tensor += SIMD_NUM_Q7;
231→                    }
232→
233→                    // rest channels
234→                    for (; cur_ch < in_tensor_ch; cur_ch++)
235→                    {
236→                        int sum = 0;
237→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
238→                        {
239→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
240→                            {
241→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
242→                                sum += *pIn;
243→                            }
244→                        }
245→
246→                        *out_tensor++ = sum / count;
247→                    }
248→                }
249→                else
250→                {
251→                    // for those outputs in boundary as there is no overlapping
252→                    // between ifm and kernel
253→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
254→                    out_tensor += in_tensor_ch;
255→                }
256→            }
257→        }
258→        in_tensor += input_len;
259→    }
260→#elif defined(ENA_DSP_ISA)
261→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
262→
263→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
264→    {
265→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
266→        {
267→            long ker_y_start = MAX(0, in_y);
268→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
269→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
270→            {
271→                long ker_x_start = MAX(0, in_x);
272→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
273→                uint32_t cur_ch;
274→
275→                if ((ker_y_end > ker_y_start) &&
276→                    (ker_x_end > ker_x_start))
277→                {
278→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
279→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
280→                    {
281→                        long_t sum_q31_0 = 0;
282→                        long_t sum_q31_1 = 0;
283→                        long_t sum_q31_2 = 0;
284→                        long_t sum_q31_3 = 0;
285→
286→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
287→                        {
288→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
289→                            {
290→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
291→                                suni_t in_q7x4 = simd_load_8(pIn, 0);
292→                                sum_q31_0 += in_q7x4.b8.b0;
293→                                sum_q31_1 += in_q7x4.b8.b1;
294→                                sum_q31_2 += in_q7x4.b8.b2;
295→                                sum_q31_3 += in_q7x4.b8.b3;
296→                            }
297→                        }
298→
299→                        suni_t out_q7x4;
300→                        out_q7x4.b8.b0 = sum_q31_0 / count;
301→                        out_q7x4.b8.b1 = sum_q31_1 / count;
302→                        out_q7x4.b8.b2 = sum_q31_2 / count;
303→                        out_q7x4.b8.b3 = sum_q31_3 / count;
304→                        simd_save_8((s8_t*)out_tensor, out_q7x4.l0);
305→                        out_tensor += SIMD_NUM_Q7;
306→                    }
307→
308→                    // rest channels
309→                    for (; cur_ch < in_tensor_ch; cur_ch++)
310→                    {
311→                        int sum = 0;
312→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
313→                        {
314→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
315→                            {
316→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
317→                                sum += *pIn;
318→                            }
319→                        }
320→
321→                        *out_tensor++ = sum / count;
322→                    }
323→                }
324→                else
325→                {
326→                    // for those outputs in boundary as there is no overlapping
327→                    // between ifm and kernel
328→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
329→                    out_tensor += in_tensor_ch;
330→                }
331→            }
332→        }
333→        in_tensor += input_len;
334→    }
335→#else
336→    int16_t   i_batch, i_ch_in, i_x, i_y;
337→    int16_t   k_x, k_y;
338→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
339→    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;
340→
341→    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
342→    {
343→        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
344→        {
345→            for (i_y = 0; i_y < out_tensor_dim; i_y++)
346→            {
347→                for (i_x = 0; i_x < out_tensor_dim; i_x++)
348→                {
349→                    int       sum = 0;
350→                    int       count = 0;
351→                    for (k_y = i_y * stride - pad; k_y < i_y * stride - pad + ker_dim; k_y++)
352→                    {
353→                        for (k_x = i_x * stride - pad; k_x < i_x * stride - pad + ker_dim; k_x++)
354→                        {
355→                            if (k_y >= 0 && k_x >= 0 && k_y < in_tensor_dim && k_x < in_tensor_dim)
356→                            {
357→                                sum += in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)];
358→                                count++;
359→                            }
360→                        }
361→                    }
362→
363→                    if (count == 0)
364→                    {
365→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = 0;
366→                    }
367→                    else
368→                    {
369→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = sum / count;
370→                    }
371→                }
372→            }
373→        }
374→        in_tensor += input_len;
375→        out_tensor += output_len;
376→    }
377→#endif
378→}
